#!/usr/bin/env bash
set -euo pipefail

# --- Extract and cache the embedded Python zipapp ---
CACHE_DIR="${HOME}/.cache/stargazer-analyser"
SCRIPT_PATH="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)/$(basename "${BASH_SOURCE[0]}")"
export ANALYZER_ROOT="$(dirname "$SCRIPT_PATH")"

PAYLOAD_LINE=$(($(grep -n '^__PAYLOAD__$' "$SCRIPT_PATH" | head -1 | cut -d: -f1) + 1))

_checksum() {
    if command -v md5sum &>/dev/null; then
        md5sum | cut -d' ' -f1
    elif command -v md5 &>/dev/null; then
        md5 -q
    else
        cksum | cut -d' ' -f1
    fi
}

CHECKSUM=$(tail -n +"$PAYLOAD_LINE" "$SCRIPT_PATH" | _checksum)
CACHED_PYZ="$CACHE_DIR/llm_validation_script_${CHECKSUM}.pyz"

if [ ! -f "$CACHED_PYZ" ]; then
    mkdir -p "$CACHE_DIR"
    tail -n +"$PAYLOAD_LINE" "$SCRIPT_PATH" | base64 -d > "$CACHED_PYZ"
    chmod +x "$CACHED_PYZ"
fi

# --- EPD-first mode switching ---
LOCAL_MODE=0
PASSTHROUGH_ARGS=()
MOUNT_PATH=""
EPD_UID=""
EPD_BATCH_ID=""
EPD_TASK_ID=""
EPD_OUTPUT=""

for arg in "$@"; do
    case "$arg" in
        --local)
            LOCAL_MODE=1
            ;;
        *)
            PASSTHROUGH_ARGS+=("$arg")
            ;;
    esac
done

# Parse known flags from PASSTHROUGH_ARGS for EPD mode
_idx=0
_nargs=${#PASSTHROUGH_ARGS[@]}
REMAINING_ARGS=()
while [ $_idx -lt "$_nargs" ]; do
    _arg="${PASSTHROUGH_ARGS[$_idx]}"
    case "$_arg" in
        --mount-path)
            _idx=$((_idx + 1))
            MOUNT_PATH="${PASSTHROUGH_ARGS[$_idx]}"
            ;;
        --uid)
            _idx=$((_idx + 1))
            EPD_UID="${PASSTHROUGH_ARGS[$_idx]}"
            REMAINING_ARGS+=("--uid" "$EPD_UID")
            ;;
        --batch-id)
            _idx=$((_idx + 1))
            EPD_BATCH_ID="${PASSTHROUGH_ARGS[$_idx]}"
            REMAINING_ARGS+=("--batch-id" "$EPD_BATCH_ID")
            ;;
        --task-id)
            _idx=$((_idx + 1))
            EPD_TASK_ID="${PASSTHROUGH_ARGS[$_idx]}"
            REMAINING_ARGS+=("--task-id" "$EPD_TASK_ID")
            ;;
        -o|--output)
            _idx=$((_idx + 1))
            EPD_OUTPUT="${PASSTHROUGH_ARGS[$_idx]}"
            REMAINING_ARGS+=("--output" "$EPD_OUTPUT")
            ;;
        *)
            REMAINING_ARGS+=("$_arg")
            ;;
    esac
    _idx=$((_idx + 1))
done

if [ "$LOCAL_MODE" -eq 1 ]; then
    exec "$CACHED_PYZ" eval ${PASSTHROUGH_ARGS[@]+"${PASSTHROUGH_ARGS[@]}"}
    exit $?
fi

# --- EPD mode: source API key and install dependencies ---
SOURCE="${MOUNT_PATH:-$(pwd)}"

if [ -f "${SOURCE}/api.txt" ]; then
    set -a
    . "${SOURCE}/api.txt"
    set +a
fi

MISSING_PKGS=()
command -v python3 &>/dev/null || MISSING_PKGS+=(python3)
command -v pip3 &>/dev/null || MISSING_PKGS+=(python3-pip)
if [[ ${#MISSING_PKGS[@]} -gt 0 ]]; then
    apt-get update -qq 2>/dev/null && apt-get install -y -qq "${MISSING_PKGS[@]}" 2>/dev/null || true
fi

pip3 install -q openai 2>/dev/null || pip install -q openai 2>/dev/null || true

# --- EPD mode: assemble task directory from flat-mounted files ---
TASK_DIR="${SOURCE}/task"

mkdir -p "${TASK_DIR}/App" "${TASK_DIR}/dockerfiles" "${TASK_DIR}/scripts" "${TASK_DIR}/patches"

_cp_if_exists() {
    [ -f "$1" ] && cp "$1" "$2" || true
}

_cp_if_exists "${SOURCE}/base.Dockerfile"      "${TASK_DIR}/dockerfiles/base.Dockerfile"
_cp_if_exists "${SOURCE}/instance.Dockerfile"   "${TASK_DIR}/dockerfiles/instance.Dockerfile"
_cp_if_exists "${SOURCE}/run_script.sh"         "${TASK_DIR}/scripts/run_script.sh"
_cp_if_exists "${SOURCE}/parse_results.sh"      "${TASK_DIR}/scripts/parse_results.sh"
_cp_if_exists "${SOURCE}/gold_patch.patch"      "${TASK_DIR}/patches/gold_patch.patch"
_cp_if_exists "${SOURCE}/test_patch.patch"      "${TASK_DIR}/patches/test_patch.patch"
_cp_if_exists "${SOURCE}/basetoinstance.patch"  "${TASK_DIR}/patches/basetoinstance.patch"
_cp_if_exists "${SOURCE}/issue.md"              "${TASK_DIR}/issue.md"
_cp_if_exists "${SOURCE}/issue_message.txt"    "${TASK_DIR}/issue_message.txt"
_cp_if_exists "${SOURCE}/rubric.json"          "${TASK_DIR}/rubric.json"
_cp_if_exists "${SOURCE}/issue_difficulty.txt" "${TASK_DIR}/issue_difficulty.txt"
_cp_if_exists "${SOURCE}/model.txt"           "${TASK_DIR}/model.txt"

if [ -f "${SOURCE}/app_contents.tar.gz" ]; then
    tar -xzf "${SOURCE}/app_contents.tar.gz" -C "${TASK_DIR}/App/"
fi

# Build final args: eval subcommand + task_dir, then output default, then user flags
FINAL_ARGS=("eval" "${TASK_DIR}")

if [ -z "$EPD_OUTPUT" ]; then
    FINAL_ARGS+=("--output" "${SOURCE}/analysis_results.json")
fi

FINAL_ARGS+=("--json")
if [ ${#REMAINING_ARGS[@]} -gt 0 ]; then
    FINAL_ARGS+=("${REMAINING_ARGS[@]}")
fi

exec "$CACHED_PYZ" "${FINAL_ARGS[@]}"
exit $?
__PAYLOAD__

